LAYER
	NAME "lotes_wgs84"
	TYPE polygon
	STATUS on
	DATA "geom FROM (SELECT gid, cod_lote, cod_mzna, cod_sect, id_lote, hab_urbana, mzna_muni, lote_muni, nro_unidad, niveles, zonificaci, estructura, area_ter, area_con, id_dist, id_prov, id_dpto, area_grafi, cuc, geom FROM cofopri.lotes_wgs84) as sbn using unique gid using srid=4326"
    FILTER ("[id_dpto]" IN "08")
	INCLUDE "configuracion/postgresql_allpa.map"
	PROJECTION
	"init=epsg:4326"
	END
	METADATA
		"layer_encoding" "Latin1"
		"wfs_encoding" "Latin1"
		"queryable" "true"		
		"wfs_title" "Formalización - Lotes (WGS84)"
		"wfs_abstract" "Formalización - Lotes (WGS84) || Organismo de Formalización de la Propiedad Informal - COFOPRI"
		"wfs_srs" "EPSG:4326"
		"gml_include_items" "all"
		"gml_featureid" "gid"
		"wfs_enable_request" "*"
		"wfs_getfeature_formatlist" "geojson,application/geojson,application/geo+json,application/json,gml,csv,SHAPE-ZIP" 
		#"wfs_additional_files_in_output" "anp_administracion_nacional.pdf,anp_administracion_nacional.lyr"
	END
	CLASS
		NAME "Lotes"
		STYLE
			COLOR 28 28 28
			OUTLINECOLOR 128 128 128
			WIDTH 1
		END
	END
END # Layer